Pattern Observer krusial untuk sistem monitoring keamanan real-time, audit log, dan notifikasi event server. Berikut implementasi bersih menggunakan `abc` untuk enforce interface dan type hinting untuk maintainability.

```python
from abc import ABC, abstractmethod
from typing import List, Any
import logging

# Konfigurasi Logging Dasar
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class Observer(ABC):
    """Interface untuk Observer. Wajib implementasi update."""

    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject(ABC):
    """Interface untuk Subject (Observable)."""

    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class SecurityEventSystem(Subject):
    """Concrete Subject untuk monitoring event keamanan."""

    def __init__(self) -> None:
        self._state: Any = None
        self._observers: List[Observer] = []

    def attach(self, observer: Observer) -> None:
        if observer not in self._observers:
            self._observers.append(observer)

    def detach(self, observer: Observer) -> None:
        if observer in self._observers:
            self._observers.remove(observer)

    def notify(self) -> None:
        """Notify semua observer. Handle exception per observer agar satu gagal tidak menghentikan semua."""
        for observer in self._observers:
            try:
                observer.update(self)
            except Exception as e:
                logging.error(f"Observer {observer.__class__.__name__} gagal update: {e}")

    def trigger_event(self, event_data: Any) -> None:
        """Set state dan trigger notify."""
        self._state = event_data
        logging.info(f"Event triggered: {event_data}")
        self.notify()

    @property
    def state(self) -> Any:
        return self._state

class LogAlertObserver(Observer):
    """Concrete Observer untuk logging alert keamanan."""

    def update(self, subject: SecurityEventSystem) -> None:
        data = subject.state
        if data.get('severity') == 'HIGH':
            logging.critical(f"ALERT KEAMANAN: {data.get('message')}")
        else:
            logging.warning(f"Event Log: {data.get('message')}")

class EmailNotificationObserver(Observer):
    """Concrete Observer untuk simulasi kirim email."""

    def update(self, subject: SecurityEventSystem) -> None:
        data = subject.state
        # Implementasi logic kirim email disini
        logging.info(f"Mengirim notifikasi email untuk: {data.get('message')}")

# --- Usage Example ---
if __name__ == "__main__":
    system = SecurityEventSystem()
    log_observer = LogAlertObserver()
    email_observer = EmailNotificationObserver()

    system.attach(log_observer)
    system.attach(email_observer)

    # Simulasi event keamanan
    system.trigger_event({'severity': 'HIGH', 'message': 'Deteksi SQL Injection Attempt'})
    system.trigger_event({'severity': 'LOW', 'message': 'User Login Success'})
```

### Catatan Teknis & Optimasi:

1.  **Error Isolation:** Perhatikan blok `try-except` di method `notify`. Dalam sistem produksi, kegagalan satu observer (misal: SMTP down) tidak boleh menghentikan notifikasi ke observer lain (misal: Log Writer).
2.  **Thread Safety:** Implementasi di atas belum thread-safe. Jika digunakan dalam environment multithreading (seperti worker server), bungkus operasi list `_observers` dengan `threading.Lock`.
3.  **Memory Leak:** Untuk aplikasi long-running, pertimbangkan menggunakan `weakref` pada list observer untuk mencegah circular reference menghambat garbage collection.
4.  **Security:** Pastikan data yang passed melalui `state` sudah disanitize jika mengandung input user sebelum diproses observer untuk mencegah Injection pada log atau notifikasi.

Gunakan pola ini untuk membangun sistem SIEM (Security Information and Event Management) sederhana atau monitoring status layanan server.
